const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
if (!body.client_file_id || !body.client_file_type) return { json: { _empty: true, status: 400, error: 'client_file_id, client_file_type required' } };
return { json: { token, client_file_id: body.client_file_id, client_file_type: body.client_file_type, vertical_id: body.vertical_id || null, client_id: body.client_id || null, file_data: body.file_data || null } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401 } };
const i = $('Extract').first().json;
return { json: { _ok: true, user_id: row.user_id, client_file_id: i.client_file_id, client_file_type: i.client_file_type, vertical_id: i.vertical_id, client_id: i.client_id, file_data: i.file_data } };

const ctx = $('Check Session').first().json;
const rules = Array.isArray($input.item.json) ? $input.item.json : [];
const data = ctx.file_data || {};
// Pick the most-specific rule per field_name: client-specific > vertical-specific > platform.
const byField = {};
rules.forEach(function (r) {
  const cur = byField[r.field_name];
  const score = (r.client_id ? 100 : 0) + (r.vertical_id ? 10 : 0) + 1;
  if (!cur || cur._score < score) { r._score = score; byField[r.field_name] = r; }
});
const effectiveRules = Object.values(byField);
let total = 0, max = 0;
const fieldScores = {};
const missing = [];
const recommended = [];
effectiveRules.forEach(function (r) {
  const w = parseInt(r.weight) || 5;
  const value = data[r.field_name];
  let complete = false;
  const v = (r.validation_rules || {});
  if (value != null && value !== '' && !(Array.isArray(value) && value.length === 0)) {
    complete = true;
    if (v.min_length && String(value).length < v.min_length) complete = false;
    if (v.regex) { try { if (!(new RegExp(v.regex).test(String(value)))) complete = false; } catch (e) {} }
    if (Array.isArray(v.must_be_in) && v.must_be_in.indexOf(value) === -1) complete = false;
  }
  max += w;
  if (complete) total += w;
  else { missing.push(r.field_name); if (r.is_required) recommended.push('Fill in required field: ' + r.field_name); }
  fieldScores[r.field_name] = { score: complete ? w : 0, max: w, complete: complete, weight: w };
});
const pct = max > 0 ? (total * 100 / max) : 0;
const status = pct >= 95 ? 'ready_for_review' : (pct >= 75 ? 'nearly_ready' : (pct >= 40 ? 'needs_work' : 'incomplete'));
return { json: { row: { client_file_id: ctx.client_file_id, client_file_type: ctx.client_file_type, total_score: total, max_score: max, status: status, field_scores: fieldScores, missing_fields: missing, recommended_actions: recommended, calculated_at: new Date().toISOString() } } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
return { json: { ok: true, score: row } };
